import { useState, useEffect } from 'react';

// 1. THE NIMHANS RULEBOOK (Hardcoded Order)
const NIMHANS_STEPS = [
  { id: 'name', label: 'Name', prompt: 'Ask for the patient\'s full name.', type: 'text' },
  { id: 'age', label: 'Age', prompt: 'Ask for the patient\'s age.', type: 'text' },
  { id: 'gender', label: 'Gender', prompt: 'Ask for gender.', type: 'choice', options: ['Male', 'Female', 'Other'] },
  { id: 'education', label: 'Education', prompt: 'What is the highest level of education?', type: 'choice', options: ['Schooling', 'Bachelor\'s', 'Master\'s', 'PhD', 'None'] },
  { 
    id: 'is_employed', 
    label: 'Employment Status', 
    prompt: 'Are they currently employed?', 
    type: 'choice', 
    options: ['Yes', 'No'] 
  },
  { 
    id: 'occupation', 
    label: 'Occupation', 
    prompt: 'What is their current occupation?', 
    type: 'text',
    condition: (data) => data.is_employed === 'Yes' // ONLY ask if employed
  },
  { id: 'complaints', label: 'Chief Complaints', prompt: 'What are the main reasons for seeking consultation?', type: 'text' }
];

export const useConversation = () => {
  const [messages, setMessages] = useState([]);
  const [isTyping, setIsTyping] = useState(false);
  const [userData, setUserData] = useState({});
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [currentStep, setCurrentStep] = useState(null);

  // Helper to find the next valid step based on NIMHANS conditions
  const getNextValidStepIndex = (index, data) => {
    let next = index;
    while (next < NIMHANS_STEPS.length) {
      const step = NIMHANS_STEPS[next];
      if (!step.condition || step.condition(data)) {
        return next;
      }
      next++; // Skip if condition not met
    }
    return null; // End of protocol
  };

  const callOllama = async (prompt, stepInfo) => {
    try {
      const systemInstructions = `
        You are a NIMHANS Clinical Assistant. 
        Tone: Professional, empathetic, clinical.
        Task: ${stepInfo.prompt}
        Format: Return ONLY a JSON object: {"message": "your conversational question"}
      `;

      const response = await fetch("http://localhost:11434/api/generate", {
        method: "POST",
        body: JSON.stringify({
          model: "mistral",
          prompt: `SYSTEM: ${systemInstructions}\nUSER: ${prompt}`,
          stream: false,
          format: "json"
        }),
      });
      const data = await response.json();
      return JSON.parse(data.response);
    } catch (error) {
      return { message: "System error. Please try again." };
    }
  };

  // Initialize
  useEffect(() => {
    const init = async () => {
      setIsTyping(true);
      const firstStep = NIMHANS_STEPS[0];
      const botRes = await callOllama("Start session.", firstStep);
      
      setMessages([{ sender: 'bot', text: botRes.message }]);
      setCurrentStep({ ...firstStep, message: botRes.message });
      setIsTyping(false);
    };
    init();
  }, []);

  const handleUserAnswer = async (answer) => {
    // 1. Save answer
    const currentStepConfig = NIMHANS_STEPS[currentStepIndex];
    const updatedData = { ...userData, [currentStepConfig.id]: answer };
    setUserData(updatedData);

    setMessages(prev => [...prev, { sender: 'user', text: answer }]);
    setIsTyping(true);

    // 2. Determine Next Step using Skip Logic
    const nextIndex = getNextValidStepIndex(currentStepIndex + 1, updatedData);
    
    if (nextIndex !== null) {
      const nextStepConfig = NIMHANS_STEPS[nextIndex];
      const botRes = await callOllama(`User answered: ${answer}. Move to next step.`, nextStepConfig);
      
      setMessages(prev => [...prev, { sender: 'bot', text: botRes.message }]);
      setCurrentStepIndex(nextIndex);
      setCurrentStep({ ...nextStepConfig, message: botRes.message });
    } else {
      // End of Protocol
      setCurrentStep(null);
    }
    setIsTyping(false);
  };

  return { messages, isTyping, currentStep, handleUserAnswer, userData };
};
